import {atom, selector} from "recoil";
import Product from "../model/product";
import menu from "../../static/menu.json";
import SelectedProduct from "../model/selectedProduct";

const products: any[] = menu.data

export const productListState = atom<Product[]>(
    {
        key: 'productListState',
        default: products as Product[]
    }
)

export const selectedProductState = atom<SelectedProduct[]>(
    {
        key: 'selectedProductList',
        default: []
    }
)

export const selectedProductsStatState = selector(
    {
        key: 'selectedProductNumState',
        get: ({get}) => {
            const products = get(selectedProductState)
            let count = products.reduce((sum, product) =>product.count + sum, 0)
            let subtotal = products.reduce((sum, product) => product.count * product.price + sum, 0)
            return {
                count,
                subtotal
            }
        }
    }
)


export const detailCardState = atom<Product | null>({
        key: 'detailCardState',
        default: null,
    }
)


export default productListState






