import React, {useState} from 'react'
import './cartContrl.css'
import '../../css/icon.css'
import {useRecoilState} from "recoil";
import {selectedProductState} from "../states/productListState";
import Product from "../model/product";
import SpecificationCard from "../specificationCard/specificicationCard";
import SelectedProduct from "../model/selectedProduct";


function replaceItemAtIndex(arr: any, index: any, newValue: any) {
    return [...arr.slice(0, index), newValue, ...arr.slice(index + 1)];
}

function removeItemAtIndex(arr: any, index: any) {
    return [...arr.slice(0, index), ...arr.slice(index + 1)];
}

const CartControl = ({...product}: Product) => {
    const [selectedProduct, setSelectedProduct] = useRecoilState(selectedProductState);
    const idx = selectedProduct.findIndex((listItem) => listItem.productUUID === product.uuid)

    const [showSpecification, setShowSpecification] = useState(false);

    let current: SelectedProduct
    current = idx == -1 ? current = {
        uuid: product.uuid,
        productUUID: product.uuid,
        name: product.name,
        price: product.price,
        count: 0,
        contentDetail: []
    } : selectedProduct[idx]

    const decreaseCart = (e: React.MouseEvent) => {
        e.stopPropagation()
        if (current.count > 0) {
            const newList = replaceItemAtIndex(selectedProduct, idx, {
                ...current,
                count: current.count - 1,
            });
            setSelectedProduct(newList)
        }
    }

    const addCart = (e: React.MouseEvent) => {
        e.stopPropagation()
        if (idx == -1) {
            current.count++
            setSelectedProduct([...selectedProduct,current])
        } else {
            setSelectedProduct(replaceItemAtIndex(selectedProduct, idx, {
                ...current,
                count: current.count + 1,
            }))
        }


    }

    const selectionEvent = (e: React.MouseEvent) => {
        e.stopPropagation()
        setShowSpecification(true)
    }

    if (product.specifications?.length) {
        return (
            <>
                {<div className="cart-control">
                    <div className="choose" onClick={selectionEvent}>
                        + Seleccione
                    </div>
                    <div className="choose-num">1</div>
                </div>
                }
                {showSpecification &&
                <div className="specification-card-container">
                    <SpecificationCard {...product} />
                </div>
                }
            </>
        )
    } else {
        return (
            <div className="cart-control">
                <div className={'cart-decrease' + (current.count ? ' move' : '')}
                     onClick={decreaseCart}>
                    <span className="inner icon-remove_circle_outline"/>
                </div>

                <div className="cart-count"
                     style={current.count ?
                         {} : {display: 'none'}}>{current.count}</div>
                <div className="cart-add icon-add_circle" onClick={addCart}/>
            </div>
        );
    }
}

export default CartControl
