import Product from "../model/product";
import React from "react";
import Specification from "../model/specification";



const SpecificationCard = ({...product}:Product) => {


    const SpecificationContent = (specification: Specification) => {
        return (
            <div className="specification-container">
                <div className="specification-title">
                    {specification.name}
                </div>
                <div className="specification-attr">

                    {specification.content.map((item => {
                        return <div key={item.uuid} className={item.chosen ? "tag-chosen" : "tag"}>
                            {item.name}
                        </div>
                    }))}
                </div>
            </div>
        )

    }

    return (
        <>
            <div className="card-title">
                {product.name}
            </div>
            {product.specifications &&
            product.specifications?.map((elem) => {
                return <SpecificationContent key={elem.uuid} uuid={elem.uuid} name={elem.name}
                                          description={elem.description}
                                          mandatory={elem.mandatory} multiChoice={elem.multiChoice}
                                          content={elem.content}/>
            })
            }
        </>
    )


}

export default SpecificationCard
