import React from 'react';
import ProductComponent from '../product/product';
import Product from "../model/product";
import {useRecoilState, useRecoilValue} from "recoil";
import {detailCardState, productListState} from "../states/productListState";
import DetailCard from "../detailCard/detailCard";
import './products.css'

const ProductsComponent = () => {
    const products = useRecoilValue(productListState);
    const [detailProduct, setDetailProduct] = useRecoilState(detailCardState)
    const html = document.querySelector("html") as HTMLElement

    if (detailProduct){
        html.style.overflow='hidden'
    }

    return (
        <body>
        <div className="menu-container">
            {
                products.map((item: Product) => {
                    return <ProductComponent key={item.uuid} {...item as Product}/>
                })
            }

            {detailProduct && <div className="card-mask">
                <DetailCard {...detailProduct}/>
                <div className="close disable-selection" onClick={() =>setDetailProduct(null)}>
                    <button onClick={() => {
                        html.style.overflow = 'scroll'
                    }}>X
                    </button>
                </div>
            </div>}
        </div>

        </body>
    )
}

export default ProductsComponent;
