import React from 'react';
import CategoriesComponent from './components/category/categories';
import HeaderComponent from './components/header/header';
import ProductsComponent from './components/productList/products';
import Category from "./components/model/category";
import ShopCart from "./components/shoopCart/shopCart";
import category from "./static/category.json";
import {RecoilRoot} from "recoil";
import '../src/css/main.css'

function App() {
    const categories: Category[] = category as Category[]
    return (
        <div className="">
            <RecoilRoot>
                <HeaderComponent/>
                <CategoriesComponent categories={categories}/>
                <ProductsComponent/>
                <ShopCart/>
            </RecoilRoot>
        </div>
    );
}

export default App;
