import Product from '../model/product';
import './product.css'
import CartControl from "../cartControl/cartControl";
import {useSetRecoilState} from "recoil";
import {detailCardState} from "../states/productListState";
import React from 'react-dom';
import {getPriceText} from "../utils/utils";

const ProductComponent = ({...product}: Product) => {
   const setDetailProduct = useSetRecoilState(detailCardState)

    return (
        <div className="food-wrapper" onClick={() => setDetailProduct(product)}>
            <img className="product-img" src={product.icon} alt={product.name}/>
            <div className="product-info">
                <h2 className="product-name">{product.name}</h2>
                <p className="product-description">{product.description}</p>
                <div className='price-wrapper'>
                    {product.price &&
                    <>
                        <span className="product-price">{getPriceText(product.price)}</span>
                        <span className="product-price">&nbsp;€</span>
                    </>}

                    <div className="cart-control-container"><CartControl {...product}/></div>
                </div>
            </div>

        </div>
    )
}


export default ProductComponent
