import Product from "../model/product";
import React from "react";
import './detailCard.css'
import CartControl from "../cartControl/cartControl";
import {getPriceText} from "../utils/utils";
import allergen from "../model/allergen";


export const DetailCard = ({...product}: Product) => {


    const getAllergen = (): string => {
        if (product.allergens) {
            if (product.allergens.length==1){
                return product.allergens[0].name
            }else if(product.allergens.length==2){
                return `${product.allergens[0].name} y ${product.allergens[1].name}`
            }else{
                return product.allergens.reduce((acc, allergen, idx, allergens) => {
                    if (idx == allergens.length - 1) {
                        acc += `y ${allergen.name}`
                    } else if (idx == allergens.length - 2) {
                        acc += `${allergen.name} `
                    } else {
                        acc += `${allergen.name}, `
                    }
                    return acc
                }, "")
            }

        }
        return ""

    }

    return (
        <div className="card-detail">
            <img className="product-img" src={product.image} alt={product.name}/>
            <div className="product-title">{product.name}</div>
            {product.description.length > 0 && <div className="description-info">
                <h2>Descripción</h2>
                <p>{product.description}</p>
            </div>}
            {(product.allergens!.length > 0) && <div className="allergen-info">
                <h2>Alérgenos</h2>
                <p>{getAllergen()}</p>
            </div>}
            <div className="detail-control">
                {product.price && <div className="detail-price">{getPriceText(product.price)} €</div>}
                <div className="card-control">
                    <CartControl {...product}/>
                </div>
            </div>

        </div>
    )

}

export default DetailCard
