import './shopcart.css'
import React from "react";
import {useRecoilValue} from "recoil";
import {selectedProductsStatState,} from "../states/productListState";


const ShopCart = () => {
    const {count, subtotal} = useRecoilValue(selectedProductsStatState);


    // show shop cart list
    const toggleList = (e: React.MouseEvent<HTMLDivElement>) => {
        e.preventDefault();
    }

    //order button action
    const pay = (e: React.MouseEvent) => {

    }


    const payDesc = (): string => {
        if (count === 0) {
            return 'Elija platos'
        } else {
            return 'Pedir'
        }
    }

    const payClass = (): string => {
        if (count === 0) {
            return 'not-enough'
        } else {
            return 'enough'
        }
    }

    return (

        <div className="shop-cart" key="shop-cart">
            <div className="content" onClick={toggleList}>
                <div className="content-left">
                    <div className="logo-wrapper">
                        <div className={'logo' + (count > 0 ? ' highlight' : '')}>
                            <i className={'icon-shopping_cart' + (count > 0 ? ' highlight' : '')}/>
                        </div>
                        <div className="num" style={count > 0 ? {} : {display: 'none'}}>{count}</div>
                    </div>
                    <div className={'price' + (subtotal > 0 ? ' highlight' : '')}>{subtotal.toFixed(2)}€</div>
                </div>
                <div className="content-right" onClick={pay}>
                    <div className={'pay ' + payClass()}>
                        {payDesc()}
                    </div>
                </div>
            </div>
        </div>

    )


}

export default ShopCart
