import React from 'react';
import Category from "../model/category";
import './categories.css'


interface IProp {
    name: string
    position: number | undefined
    currentPosition: number | undefined
}

const CategoryComponent = ({name, position, currentPosition}: IProp) => {

    const active = currentPosition !== undefined && position !== undefined && currentPosition === position
    return (
        <div className={"category-tag" + (active?" category-tag-active":"")}>{name}</div>
    )
}



interface IProps{
    categories: Array<Category>
}

const CategoriesComponent = (props :IProps) => {

    return (
        <div className="categories-container">{
            props.categories.map((category, index) => {
                return <CategoryComponent name={category.name} key={index} currentPosition={0} position={index}/>
            })}
        </div>
    )
}

export default CategoriesComponent;
